class Solution {
    public int shortestMatchingSubstring(String s, String p) {
        int idx1 = p.indexOf('*');
        int idx2 = p.lastIndexOf('*');
        String prefix = p.substring(0, idx1);
        String suffix = p.substring(idx2 + 1);
        int prefixLen = prefix.length();
        int suffixLen = suffix.length();
        int minLen = Integer.MAX_VALUE;

        for (int i = 0; i <= s.length() - prefixLen; i++) {
            if (s.startsWith(prefix, i)) {
                for (int j = i + prefixLen; j <= s.length() - suffixLen; j++) {
                    if (s.startsWith(suffix, j)) {
                        minLen = Math.min(minLen, j - i + suffixLen);
                    }
                }
            }
        }

        return minLen == Integer.MAX_VALUE ? -1 : minLen;
    }
}
